#!/usr/bin/env bash
# NetEng Toolkit self-installing Linux app
#
# Usage:
#   sudo bash neteng-toolkit.sh install
#   sudo bash neteng-toolkit.sh uninstall
#   sudo systemctl status neteng-toolkit
#
# The installer creates /opt/neteng-toolkit, writes a standalone offline HTML app,
# installs a systemd service, and serves the app on HTTP port 8443.

set -euo pipefail

APP_NAME="neteng-toolkit"
APP_DIR="/opt/${APP_NAME}"
APP_FILE="${APP_DIR}/index.html"
UNIT_FILE="/etc/systemd/system/${APP_NAME}.service"
PORT="8443"

require_root() {
  if [[ "${EUID}" -ne 0 ]]; then
    echo "This command must be run as root. Try: sudo bash $0 $*" >&2
    exit 1
  fi
}

install_app() {
  require_root "$@"
  if ! command -v python3 >/dev/null 2>&1; then
    echo "python3 is required to serve the toolkit. Install python3 and retry." >&2
    exit 1
  fi

  mkdir -p "${APP_DIR}"
  cat > "${APP_FILE}" <<'HTML_EOF'
<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>Offline Network Engineering Toolkit</title>
<style>
:root{--bg:#0f172a;--panel:#111c33;--card:#16243f;--text:#e5eefc;--muted:#9fb1cc;--accent:#38bdf8;--accent2:#22c55e;--danger:#fb7185;--warn:#fbbf24;--border:#29415f;--shadow:0 12px 30px #0005;--mono:ui-monospace,SFMono-Regular,Menlo,Consolas,monospace;--sans:Inter,ui-sans-serif,system-ui,-apple-system,Segoe UI,Roboto,Arial,sans-serif}body.light{--bg:#f4f7fb;--panel:#fff;--card:#ffffff;--text:#132033;--muted:#53657e;--accent:#0369a1;--accent2:#15803d;--danger:#be123c;--warn:#a16207;--border:#d4dfec;--shadow:0 10px 24px #28415a22}body.sepia{--bg:#f5eddd;--panel:#fff7e8;--card:#fffaf0;--text:#352515;--muted:#75624b;--accent:#9a5b18;--accent2:#4d7c0f;--danger:#9f1239;--warn:#9a3412;--border:#decba9;--shadow:0 10px 24px #5c391822}body.contrast{--bg:#000;--panel:#000;--card:#111;--text:#fff;--muted:#eee;--accent:#0ff;--accent2:#0f0;--danger:#f36;--warn:#ff0;--border:#fff;--shadow:none}*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--text);font-family:var(--sans);min-height:100vh}button,input,textarea,select{font:inherit}button{background:var(--accent);border:0;color:#001626;border-radius:10px;padding:.65rem .9rem;font-weight:700;cursor:pointer}button.secondary{background:transparent;color:var(--text);border:1px solid var(--border)}button.danger{background:var(--danger);color:#fff}button.small{padding:.35rem .55rem;border-radius:8px;font-size:.85rem}input,textarea,select{width:100%;background:var(--panel);color:var(--text);border:1px solid var(--border);border-radius:10px;padding:.65rem}textarea{min-height:130px;font-family:var(--mono)}label{display:block;color:var(--muted);font-size:.9rem;margin:.75rem 0 .25rem}.hidden{display:none!important}.app{display:grid;grid-template-columns:280px 1fr;min-height:100vh}.sidebar{background:var(--panel);border-right:1px solid var(--border);padding:1rem;position:sticky;top:0;height:100vh;overflow:auto}.brand{font-size:1.15rem;font-weight:900;margin-bottom:1rem}.search{margin:.75rem 0}.nav button{display:block;width:100%;text-align:left;margin:.25rem 0;background:transparent;color:var(--text);border:1px solid transparent}.nav button.active,.nav button:hover{border-color:var(--border);background:var(--card)}.main{padding:1.25rem;overflow:auto}.topbar{display:flex;gap:.75rem;justify-content:space-between;align-items:center;margin-bottom:1rem;flex-wrap:wrap}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(230px,1fr));gap:1rem}.card{background:var(--card);border:1px solid var(--border);border-radius:16px;padding:1rem;box-shadow:var(--shadow)}.tool{display:none}.tool.active{display:block}.row{display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:.75rem}.out{white-space:pre-wrap;background:var(--panel);border:1px solid var(--border);border-radius:12px;padding:1rem;min-height:70px;font-family:var(--mono);overflow:auto}.muted{color:var(--muted)}.pill{display:inline-block;border:1px solid var(--border);border-radius:999px;padding:.2rem .55rem;margin:.15rem;color:var(--muted)}table{width:100%;border-collapse:collapse}th,td{border-bottom:1px solid var(--border);text-align:left;padding:.5rem;vertical-align:top}.toast{position:fixed;right:1rem;bottom:1rem;display:grid;gap:.5rem;z-index:20}.toast div{background:var(--panel);border:1px solid var(--border);padding:.75rem 1rem;border-radius:12px;box-shadow:var(--shadow)}.modal{position:fixed;inset:0;background:#0009;display:flex;align-items:center;justify-content:center;z-index:15}.modal>div{background:var(--card);border:1px solid var(--border);border-radius:16px;padding:1rem;max-width:780px;width:92%;max-height:90vh;overflow:auto}.login{max-width:430px;margin:8vh auto}.kbd{font-family:var(--mono);border:1px solid var(--border);border-bottom-width:3px;border-radius:6px;padding:.05rem .35rem}.diagram{height:360px;background:linear-gradient(45deg,var(--panel) 25%,transparent 25%),linear-gradient(-45deg,var(--panel) 25%,transparent 25%);background-size:24px 24px;border:1px solid var(--border);border-radius:12px;position:relative;overflow:hidden}.node{position:absolute;background:var(--accent);color:#001626;border-radius:12px;padding:.5rem .75rem;font-weight:800;cursor:move}.line{position:absolute;height:2px;background:var(--muted);transform-origin:left top}@media(max-width:780px){.app{grid-template-columns:1fr}.sidebar{height:auto;position:relative}.nav{display:grid;grid-template-columns:repeat(auto-fit,minmax(160px,1fr));gap:.25rem}.main{padding:.8rem}}
</style>
</head>
<body>
<div id="login" class="login card">
  <h1>NetEng Toolkit</h1><p class="muted">Offline-first browser toolkit. Default login: <b>admin</b> / <b>admin123</b>. Change it after first login.</p>
  <label>Username</label><input id="loginUser" value="admin" autocomplete="username">
  <label>Password</label><input id="loginPass" type="password" value="admin123" autocomplete="current-password">
  <p><button onclick="login()">Login</button></p><div id="loginMsg" class="muted"></div>
</div>
<div id="app" class="app hidden">
  <aside class="sidebar"><div class="brand">🛠 NetEng Toolkit</div><input id="launcher" class="search" placeholder="Search tools or press /"><div class="nav" id="nav"></div></aside>
  <main class="main"><div class="topbar"><div><h2 id="title">Dashboard</h2><div id="subtitle" class="muted">Standalone offline network engineering toolkit</div></div><div class="row" style="max-width:620px"><select id="theme" onchange="setTheme(this.value)"><option>dark</option><option>light</option><option>sepia</option><option value="contrast">high contrast</option></select><button class="secondary" onclick="openModal('settings')">Settings</button><button class="secondary" onclick="logout()">Logout</button></div></div><section id="content"></section></main>
</div><div id="modal" class="modal hidden"></div><div id="toast" class="toast"></div>
<script>
'use strict';
const $=id=>document.getElementById(id);const enc=new TextEncoder();let db,workspace={notes:'',tasks:[],inventory:[],kb:[],ouis:{'001A2B':'Example Networks','AABBCC':'Lab Vendor','F4F5E8':'Cisco Systems'},templates:{'Cisco interface':'interface {{interface}}\n description {{description}}\n ip address {{ip}} {{mask}}\n no shutdown','OSPF':'router ospf {{process}}\n network {{network}} {{wildcard}} area {{area}}'},diagram:{nodes:[],links:[]}};
const tools=[['dash','Dashboard','Home','Overview, backup, launcher'],['ipv4','IPv4 subnet calculator','Addressing','IPv4 network, broadcast, hosts'],['wildcard','Wildcard/mask converter','Addressing','Cisco wildcard and masks'],['vlsm','VLSM planner','Addressing','Allocate variable-length subnets'],['ipv6','IPv6 calculator','Addressing','Expand, compress, prefix info'],['mac','MAC/OUI lookup','Addressing','Normalize MAC and lookup vendor'],['convert','Encoders/decoders','Crypto','Base64, hex, binary, URL'],['hash','Hash generator','Crypto','SHA digest generation'],['password','Password generator','Crypto','Random passwords'],['templates','Config templates','Config','Reusable templates'],['csvconfig','CSV-to-config generator','Config','Render templates from CSV'],['jinja','Jinja-like playground','Config','Simple variable replacement'],['diff','Config diff','Config','Line-by-line config comparison'],['acl','ACL builder','Config','Cisco-style ACL lines'],['topology','CDP/LLDP topology parser','Config','Extract adjacencies'],['routetest','Route-map/prefix-list tester','Config','CIDR match simulation'],['cheatsheet','Cisco cheatsheet','Config','Common commands'],['kb','Local knowledge base','Config','IndexedDB notes'],['ports','Port reference','Operations','Common TCP/UDP ports'],['bandwidth','Bandwidth calculator','Operations','Unit and transfer estimates'],['mtu','MTU/MSS calculator','Operations','Overhead and MSS'],['poe','PoE budget calculator','Operations','Switch power planning'],['tz','Timezone/change planner','Operations','Plan maintenance windows'],['diagram','Diagram tool','Operations','Local draggable diagram'],['scratch','Scratchpad','Operations','Persistent notes'],['tasks','Task tracker','Operations','Local task list'],['inventory','Inventory','Operations','Asset inventory'],['regex','Regex tester','Operations','Pattern testing'],['viewer','JSON/YAML/XML viewer','Operations','Pretty validation']];
function toast(m){let d=document.createElement('div');d.textContent=m;$('toast').appendChild(d);setTimeout(()=>d.remove(),3500)}function saveLocal(){localStorage.netengToolkit=JSON.stringify({theme:document.body.className,session:localStorage.session,auth:localStorage.auth})}function getAuth(){return JSON.parse(localStorage.auth||'null')}async function pbkdf2(pass,salt){let key=await crypto.subtle.importKey('raw',enc.encode(pass),'PBKDF2',false,['deriveBits']);let bits=await crypto.subtle.deriveBits({name:'PBKDF2',salt:enc.encode(salt),iterations:150000,hash:'SHA-256'},key,256);return hex(new Uint8Array(bits))}function rand(n=16){let a=new Uint8Array(n);crypto.getRandomValues(a);return hex(a)}function hex(buf){return Array.from(buf).map(b=>b.toString(16).padStart(2,'0')).join('')}async function ensureAuth(){if(!localStorage.auth){let salt=rand(16),hash=await pbkdf2('admin123',salt);localStorage.auth=JSON.stringify({user:'admin',salt,hash});}}async function login(){let a=getAuth();let h=await pbkdf2($('loginPass').value,a.salt);if($('loginUser').value===a.user&&h===a.hash){localStorage.session='1';$('login').classList.add('hidden');$('app').classList.remove('hidden');initApp();toast('Logged in')}else $('loginMsg').textContent='Invalid credentials'}function logout(){delete localStorage.session;location.reload()}async function changePassword(){let a=getAuth(),cur=$('curPass').value,nu=$('newPass').value;if(await pbkdf2(cur,a.salt)!==a.hash)return toast('Current password is incorrect');if(nu.length<8)return toast('Use at least 8 characters');a.salt=rand(16);a.hash=await pbkdf2(nu,a.salt);localStorage.auth=JSON.stringify(a);toast('Password changed')}
function openDB(){return new Promise((res,rej)=>{let r=indexedDB.open('neteng-toolkit',1);r.onupgradeneeded=()=>r.result.createObjectStore('workspace');r.onsuccess=()=>{db=r.result;res()};r.onerror=()=>rej(r.error)})}function idbGet(k){return new Promise(res=>{let tx=db.transaction('workspace','readonly').objectStore('workspace').get(k);tx.onsuccess=()=>res(tx.result);tx.onerror=()=>res(null)})}function idbSet(k,v){return new Promise(res=>{let tx=db.transaction('workspace','readwrite').objectStore('workspace').put(v,k);tx.onsuccess=()=>res()})}async function loadWorkspace(){workspace=Object.assign(workspace,await idbGet('data')||{});document.body.className=localStorage.theme||'dark';$('theme').value=document.body.className==='contrast'?'contrast':document.body.className||'dark'}async function persist(){await idbSet('data',workspace)}async function exportBackup(){await persist();let data={version:1,exported:new Date().toISOString(),workspace,auth:getAuth(),theme:document.body.className};download('neteng-toolkit-backup.json',JSON.stringify(data,null,2),'application/json')}function importBackupFile(f){let rd=new FileReader();rd.onload=async()=>{let d=JSON.parse(rd.result);workspace=d.workspace||workspace;if(d.auth)localStorage.auth=JSON.stringify(d.auth);if(d.theme)setTheme(d.theme);await persist();toast('Backup imported');show('dash')};rd.readAsText(f)}function download(name,data,type='text/plain'){let a=document.createElement('a');a.href=URL.createObjectURL(new Blob([data],{type}));a.download=name;a.click();URL.revokeObjectURL(a.href)}async function syncFile(){if(!window.showSaveFilePicker)return toast('File System Access API not supported in this browser');let h=await showSaveFilePicker({suggestedName:'neteng-toolkit-sync.json',types:[{description:'JSON',accept:{'application/json':['.json']}}]});let w=await h.createWritable();await w.write(JSON.stringify({workspace,auth:getAuth(),theme:document.body.className},null,2));await w.close();toast('Synced JSON file')}
function setTheme(t){document.body.className=t==='high contrast'?'contrast':t;localStorage.theme=document.body.className;saveLocal()}function openModal(kind){let html='<div><button class="secondary small" style="float:right" onclick="closeModal()">Close</button>';if(kind==='settings')html+='<h2>Settings</h2><p>Change password, export/import backups, or sync a JSON file.</p><div class="row"><div><label>Current password</label><input id="curPass" type="password"><label>New password</label><input id="newPass" type="password"><p><button onclick="changePassword()">Change password</button></p></div><div><label>Import backup JSON</label><input type="file" accept="application/json" onchange="importBackupFile(this.files[0])"><p><button onclick="exportBackup()">Export backup</button> <button class="secondary" onclick="syncFile()">Sync JSON file</button></p><p class="muted">All state stays local unless you import, export, or sync.</p></div></div>';html+='</div>';$('modal').innerHTML=html;$('modal').classList.remove('hidden')}function closeModal(){$('modal').classList.add('hidden')}
function nav(){let q=$('launcher').value.toLowerCase();$('nav').innerHTML=tools.filter(t=>(t.join(' ').toLowerCase().includes(q))).map(t=>`<button onclick="show('${t[0]}')"><b>${t[1]}</b><br><span class="muted">${t[2]}</span></button>`).join('')}function show(id){let t=tools.find(x=>x[0]===id)||tools[0];$('title').textContent=t[1];$('subtitle').textContent=t[3];$('content').innerHTML=render(id);wire(id);document.querySelectorAll('.nav button').forEach(b=>b.classList.toggle('active',b.textContent.includes(t[1])))}
function render(id){let box=(inner)=>`<div class="card">${inner}</div>`;let out='<div id="out" class="out"></div>';switch(id){case'dash':return `<div class="grid">${tools.slice(1).map(t=>`<div class="card"><h3>${t[1]}</h3><p class="muted">${t[3]}</p><button onclick="show('${t[0]}')">Open</button></div>`).join('')}</div><p>${box('<h3>Backup</h3><button onclick="exportBackup()">Export JSON</button> <button class="secondary" onclick="openModal(\'settings\')">Import / Settings</button> <button class="secondary" onclick="syncFile()">Optional JSON Sync</button>')}</p>`;case'ipv4':return box('<div class="row"><div><label>IP address</label><input id="ip" value="192.168.10.23"></div><div><label>CIDR</label><input id="cidr" value="24"></div></div><p><button id="calc">Calculate</button></p>'+out);case'wildcard':return box('<label>Mask or wildcard</label><input id="mask" value="255.255.255.0"><p><button id="calc">Convert</button></p>'+out);case'vlsm':return box('<label>Base network CIDR</label><input id="base" value="10.0.0.0/24"><label>Host requirements, one per line</label><textarea id="req">60\n30\n12\n6</textarea><p><button id="calc">Plan</button></p>'+out);case'ipv6':return box('<label>IPv6 address/prefix</label><input id="v6" value="2001:db8::1/64"><p><button id="calc">Analyze</button></p>'+out);case'mac':return box('<label>MAC address</label><input id="macin" value="00:1a:2b:aa:bb:cc"><p><button id="calc">Lookup/Convert</button> <button class="secondary" id="expOui">Export OUI</button></p><label>Import OUI JSON map</label><input type="file" id="ouiFile" accept="application/json">'+out);case'convert':return box('<label>Input</label><textarea id="txt">hello network</textarea><div class="row"><button id="b64">Base64</button><button id="hexenc">Hex</button><button id="binenc">Binary</button><button id="urlenc">URL</button></div>'+out);case'hash':return box('<label>Input</label><textarea id="txt">config text</textarea><p><button id="calc">SHA-256 / SHA-384 / SHA-512</button></p>'+out);case'password':return box('<div class="row"><div><label>Length</label><input id="len" value="20"></div><div><label>Count</label><input id="count" value="5"></div></div><p><button id="calc">Generate</button></p>'+out);case'templates':return box('<label>Name</label><input id="name"><label>Template</label><textarea id="tpl"></textarea><p><button id="saveTpl">Save</button></p><div id="tplList"></div>');case'csvconfig':return box('<label>Template</label><textarea id="tpl">interface {{interface}}\n description {{description}}\n ip address {{ip}} {{mask}}</textarea><label>CSV</label><textarea id="csv">interface,description,ip,mask\nGi0/1,Uplink,10.0.0.1,255.255.255.252</textarea><p><button id="calc">Generate</button></p>'+out);case'jinja':return box('<label>Template</label><textarea id="tpl">hostname {{hostname}}\ninterface {{interface}}</textarea><label>Variables JSON</label><textarea id="vars">{"hostname":"R1","interface":"Gi0/0"}</textarea><p><button id="calc">Render</button></p>'+out);case'diff':return box('<div class="row"><div><label>Config A</label><textarea id="a">line one\nline two</textarea></div><div><label>Config B</label><textarea id="b">line one\nline three</textarea></div></div><p><button id="calc">Diff</button></p>'+out);case'acl':return box('<div class="row"><input id="act" value="permit"><input id="proto" value="tcp"><input id="src" value="any"><input id="dst" value="host 10.0.0.10"><input id="port" value="eq 443"></div><p><button id="calc">Build ACL</button></p>'+out);case'topology':return box('<label>Paste CDP/LLDP text</label><textarea id="txt">Device ID: SW2\nInterface: Gig 1/0/1, Port ID: Gig 1/0/24\nSystem Name: AP1\nPort id: eth0</textarea><p><button id="calc">Parse</button></p>'+out);case'routetest':return box('<label>Prefix-list lines</label><textarea id="pl">permit 10.0.0.0/8 le 24\ndeny 0.0.0.0/0 le 32</textarea><label>Route prefix</label><input id="route" value="10.1.2.0/24"><p><button id="calc">Test</button></p>'+out);case'cheatsheet':return box('<input id="cheatq" placeholder="Filter commands"><div id="cheats"></div>');case'kb':return box('<label>Title</label><input id="kbtitle"><label>Note</label><textarea id="kbbody"></textarea><p><button id="addKb">Add</button></p><div id="kblist"></div>');case'ports':return box('<input id="portq" placeholder="Search port"><div id="ports"></div>');case'bandwidth':return box('<div class="row"><div><label>Size GB</label><input id="gb" value="10"></div><div><label>Mbps</label><input id="mbps" value="100"></div></div><p><button id="calc">Calculate</button></p>'+out);case'mtu':return box('<div class="row"><input id="mtuval" value="1500"><input id="over" value="40"></div><p><button id="calc">Calculate MSS</button></p>'+out);case'poe':return box('<label>Switch budget watts</label><input id="budget" value="370"><label>Device watts, one per line</label><textarea id="watts">15.4\n30\n7\n7</textarea><p><button id="calc">Calculate</button></p>'+out);case'tz':return box('<label>Local date/time</label><input id="dt" type="datetime-local"><label>Duration hours</label><input id="dur" value="2"><p><button id="calc">Plan</button></p>'+out);case'diagram':return box('<p><button id="addNode">Add node</button> <button id="saveDiag" class="secondary">Save</button></p><div id="canvas" class="diagram"></div>');case'scratch':return box('<textarea id="scratch"></textarea><p><button id="saveScratch">Save</button></p>');case'tasks':return box('<div class="row"><input id="taskText" placeholder="Task"><button id="addTask">Add</button></div><div id="taskList"></div>');case'inventory':return box('<div class="row"><input id="host" placeholder="Hostname"><input id="ipaddr" placeholder="IP"><input id="role" placeholder="Role"><button id="addInv">Add</button></div><div id="invList"></div>');case'regex':return box('<label>Regex</label><input id="re" value="\\b\\d{1,3}(?:\\.\\d{1,3}){3}\\b"><label>Text</label><textarea id="txt">Router 10.0.0.1</textarea><p><button id="calc">Test</button></p>'+out);case'viewer':return box('<label>JSON/YAML/XML</label><textarea id="txt">{"hostname":"r1","interfaces":["Gi0/0"]}</textarea><p><button id="calc">Format / validate</button></p>'+out);default:return box('Tool not found')}}
function ip2n(ip){return ip.split('.').reduce((a,o)=>(a<<8)+(parseInt(o)||0),0)>>>0}function n2ip(n){return[24,16,8,0].map(s=>(n>>>s)&255).join('.')}function mask(c){return c==0?0:(0xffffffff<<(32-c))>>>0}function cidrSize(h){let bits=Math.ceil(Math.log2(Number(h)+2));return 32-bits}function matchCidr(r,n){let [a,c]=r.split('/');return (ip2n(a)&mask(+c))===(ip2n(n)&mask(+c))}function renderTpl(t,v){return t.replace(/{{\s*([\w.-]+)\s*}}/g,(_,k)=>v[k]??'')}function parseCSV(s){let [h,...rows]=s.trim().split(/\r?\n/);let heads=h.split(',').map(x=>x.trim());return rows.map(r=>Object.fromEntries(r.split(',').map((v,i)=>[heads[i],v.trim()]))) }
function wire(id){let o=$('out');if(id==='ipv4')$('calc').onclick=()=>{let ip=ip2n($('ip').value),c=+$('cidr').value,m=mask(c),net=ip&m,bc=net|(~m>>>0);o.textContent=`Network: ${n2ip(net)}/${c}\nMask: ${n2ip(m)}\nWildcard: ${n2ip(~m>>>0)}\nFirst host: ${n2ip(net+1)}\nLast host: ${n2ip(bc-1)}\nBroadcast: ${n2ip(bc)}\nUsable hosts: ${Math.max(0,2**(32-c)-2)}`};if(id==='wildcard')$('calc').onclick=()=>{let n=ip2n($('mask').value);o.textContent=`Input: ${$('mask').value}\nInverted: ${n2ip(~n>>>0)}\nCIDR if mask: /${(n>>>0).toString(2).replace(/0/g,'').length}`};if(id==='vlsm')$('calc').onclick=()=>{let [b,c]=$('base').value.split('/'),cur=ip2n(b)&mask(+c),end=cur+(2**(32-+c))-1,lines=$('req').value.split(/\s+/).filter(Boolean).map(Number).sort((a,b)=>b-a),res=[];for(let h of lines){let cc=cidrSize(h),size=2**(32-cc);if(cur+size-1>end){res.push(`No room for ${h}`);continue}res.push(`${h} hosts -> ${n2ip(cur)}/${cc} usable ${n2ip(cur+1)}-${n2ip(cur+size-2)}`);cur+=size}o.textContent=res.join('\n')};if(id==='ipv6')$('calc').onclick=()=>{let [addr,p='64']=$('v6').value.split('/');let parts=addr.split('::');let left=parts[0]?parts[0].split(':'):[],right=parts[1]?parts[1].split(':'):[];let fill=Array(8-left.length-right.length).fill('0');let full=[...left,...fill,...right].map(x=>x.padStart(4,'0')).join(':');o.textContent=`Expanded: ${full}\nCompressed input: ${addr}\nPrefix length: /${p}\nInterface bits: ${128-Number(p)}\nDocumentation prefix? ${addr.toLowerCase().startsWith('2001:db8')?'yes':'no'}`};if(id==='mac'){ $('calc').onclick=()=>{let raw=$('macin').value.replace(/[^a-fA-F0-9]/g,'').toUpperCase().padEnd(12,'0').slice(0,12),oui=raw.slice(0,6);o.textContent=`Colon: ${raw.match(/../g).join(':')}\nDash: ${raw.match(/../g).join('-')}\nCisco: ${raw.match(/..../g).join('.')}\nOUI: ${oui}\nVendor: ${workspace.ouis[oui]||'Unknown'}`};$('expOui').onclick=()=>download('oui-map.json',JSON.stringify(workspace.ouis,null,2),'application/json');$('ouiFile').onchange=e=>{let r=new FileReader();r.onload=async()=>{Object.assign(workspace.ouis,JSON.parse(r.result));await persist();toast('OUI map imported')};r.readAsText(e.target.files[0])}}if(id==='convert'){let val=()=>$('txt').value;$('b64').onclick=()=>o.textContent=`Encode: ${btoa(unescape(encodeURIComponent(val())))}\nDecode attempt: ${(()=>{try{return decodeURIComponent(escape(atob(val())))}catch(e){return 'not valid base64'}})()}`;$('hexenc').onclick=()=>o.textContent=Array.from(enc.encode(val())).map(b=>b.toString(16).padStart(2,'0')).join(' ');$('binenc').onclick=()=>o.textContent=Array.from(enc.encode(val())).map(b=>b.toString(2).padStart(8,'0')).join(' ');$('urlenc').onclick=()=>o.textContent=`Encode: ${encodeURIComponent(val())}\nDecode: ${decodeURIComponent(val())}`;}if(id==='hash')$('calc').onclick=async()=>{let data=enc.encode($('txt').value),r=[];for(let alg of ['SHA-256','SHA-384','SHA-512'])r.push(`${alg}: ${hex(new Uint8Array(await crypto.subtle.digest(alg,data)))}`);o.textContent=r.join('\n')};if(id==='password')$('calc').onclick=()=>{let chars='ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz23456789!@#$%^&*_-+=',arr=[];for(let j=0;j<+$('count').value;j++){let bytes=new Uint8Array(+$('len').value);crypto.getRandomValues(bytes);arr.push(Array.from(bytes,b=>chars[b%chars.length]).join(''))}o.textContent=arr.join('\n')};if(id==='templates'){let list=()=>{$('tplList').innerHTML=Object.entries(workspace.templates).map(([k,v])=>`<div class="card"><b>${k}</b><pre>${v.replace(/[<>&]/g,c=>({'<':'&lt;','>':'&gt;','&':'&amp;'}[c]))}</pre><button class="small" onclick="$('name').value='${k}';$('tpl').value=workspace.templates['${k}']">Edit</button></div>`).join('')};$('saveTpl').onclick=async()=>{workspace.templates[$('name').value]=$('tpl').value;await persist();list();toast('Template saved')};list()}if(id==='csvconfig')$('calc').onclick=()=>o.textContent=parseCSV($('csv').value).map(v=>renderTpl($('tpl').value,v)).join('\n!\n');if(id==='jinja')$('calc').onclick=()=>o.textContent=renderTpl($('tpl').value,JSON.parse($('vars').value));if(id==='diff')$('calc').onclick=()=>{let a=$('a').value.split('\n'),b=$('b').value.split('\n'),max=Math.max(a.length,b.length),r=[];for(let i=0;i<max;i++)if(a[i]!==b[i])r.push(`- ${a[i]||''}\n+ ${b[i]||''}`);o.textContent=r.join('\n')||'No differences'};if(id==='acl')$('calc').onclick=()=>o.textContent=`access-list 101 ${$('act').value} ${$('proto').value} ${$('src').value} ${$('dst').value} ${$('port').value}`;if(id==='topology')$('calc').onclick=()=>{let lines=$('txt').value.split('\n'),r=[];for(let i=0;i<lines.length;i++){if(/Device ID|System Name/i.test(lines[i]))r.push(`${lines[i].split(':').pop().trim()} via ${(lines[i+1]||'').trim()}`)}o.textContent=r.join('\n')};if(id==='routetest')$('calc').onclick=()=>{let route=$('route').value,[rip,rc]=route.split('/'),res='implicit deny';for(let l of $('pl').value.split('\n')){let m=l.match(/(permit|deny)\s+(\S+)\s*(?:le\s+(\d+))?/);if(m&&matchCidr(m[2],rip)&&(+rc>=+m[2].split('/')[1])&&(!m[3]||+rc<=+m[3])){res=m[1]+' by '+l;break}}o.textContent=res};if(id==='cheatsheet'){let data=['show ip interface brief','show interfaces status','show cdp neighbors detail','show lldp neighbors detail','show ip route','show ip bgp summary','show spanning-tree root','show etherchannel summary','show access-lists','show logging','configure terminal','copy running-config startup-config'];let draw=()=>{$('cheats').innerHTML=data.filter(x=>x.includes($('cheatq').value)).map(x=>`<span class="pill">${x}</span>`).join('')};$('cheatq').oninput=draw;draw()}if(id==='kb'){let draw=()=>{$('kblist').innerHTML=workspace.kb.map((n,i)=>`<div class="card"><b>${n.title}</b><p>${n.body}</p><button class="small danger" onclick="workspace.kb.splice(${i},1);persist();show('kb')">Delete</button></div>`).join('')};$('addKb').onclick=async()=>{workspace.kb.push({title:$('kbtitle').value,body:$('kbbody').value,ts:Date.now()});await persist();draw()};draw()}if(id==='ports'){let data=[[20,'FTP data'],[21,'FTP'],[22,'SSH'],[23,'Telnet'],[25,'SMTP'],[53,'DNS'],[67,'DHCP server'],[68,'DHCP client'],[80,'HTTP'],[123,'NTP'],[161,'SNMP'],[389,'LDAP'],[443,'HTTPS'],[514,'Syslog'],[636,'LDAPS'],[993,'IMAPS'],[995,'POP3S'],[1812,'RADIUS auth'],[1813,'RADIUS acct'],[3389,'RDP'],[5060,'SIP']];let draw=()=>{$('ports').innerHTML='<table><tr><th>Port</th><th>Service</th></tr>'+data.filter(x=>x.join(' ').toLowerCase().includes($('portq').value.toLowerCase())).map(x=>`<tr><td>${x[0]}</td><td>${x[1]}</td></tr>`).join('')+'</table>'};$('portq').oninput=draw;draw()}if(id==='bandwidth')$('calc').onclick=()=>{let bits=+$('gb').value*8e9,sec=bits/(+$('mbps').value*1e6);o.textContent=`${Math.round(sec)} seconds\n${(sec/60).toFixed(1)} minutes\n${(sec/3600).toFixed(2)} hours`};if(id==='mtu')$('calc').onclick=()=>o.textContent=`MSS: ${+$('mtuval').value-+$('over').value}\nCommon TCP/IP overhead is 40 bytes; add tunnel overhead as needed.`;if(id==='poe')$('calc').onclick=()=>{let vals=$('watts').value.split(/\s+/).filter(Boolean).map(Number),sum=vals.reduce((a,b)=>a+b,0);o.textContent=`Devices: ${vals.length}\nRequired: ${sum.toFixed(1)} W\nBudget: ${$('budget').value} W\nRemaining: ${($('budget').value-sum).toFixed(1)} W`};if(id==='tz')$('calc').onclick=()=>{let d=new Date($('dt').value||Date.now()),end=new Date(d.getTime()+$('dur').value*3600000);o.textContent=['UTC','America/New_York','America/Chicago','America/Denver','America/Los_Angeles','Europe/London','Asia/Tokyo'].map(t=>`${t}: ${d.toLocaleString('en-US',{timeZone:t})} - ${end.toLocaleString('en-US',{timeZone:t})}`).join('\n')};if(id==='diagram'){let c=$('canvas'),drag=null;let draw=()=>{c.innerHTML='';workspace.diagram.nodes.forEach((n,i)=>{let d=document.createElement('div');d.className='node';d.textContent=n.name;d.style.left=n.x+'px';d.style.top=n.y+'px';d.onpointerdown=e=>{drag={i,dx:e.offsetX,dy:e.offsetY};d.setPointerCapture(e.pointerId)};d.onpointermove=e=>{if(drag&&drag.i===i){n.x=e.offsetX+d.offsetLeft-drag.dx;n.y=e.offsetY+d.offsetTop-drag.dy;d.style.left=n.x+'px';d.style.top=n.y+'px'}};d.onpointerup=()=>drag=null;c.appendChild(d)})};$('addNode').onclick=()=>{workspace.diagram.nodes.push({name:'Node '+(workspace.diagram.nodes.length+1),x:30+workspace.diagram.nodes.length*30,y:40});draw()};$('saveDiag').onclick=async()=>{await persist();toast('Diagram saved')};draw()}if(id==='scratch'){$('scratch').value=workspace.notes||'';$('saveScratch').onclick=async()=>{workspace.notes=$('scratch').value;await persist();toast('Saved')}}if(id==='tasks'){let draw=()=>{$('taskList').innerHTML=workspace.tasks.map((t,i)=>`<div><label><input style="width:auto" type="checkbox" ${t.done?'checked':''} onchange="workspace.tasks[${i}].done=this.checked;persist()"> ${t.text}</label></div>`).join('')};$('addTask').onclick=async()=>{workspace.tasks.push({text:$('taskText').value,done:false});await persist();draw()};draw()}if(id==='inventory'){let draw=()=>{$('invList').innerHTML='<table><tr><th>Host</th><th>IP</th><th>Role</th></tr>'+workspace.inventory.map(x=>`<tr><td>${x.host}</td><td>${x.ip}</td><td>${x.role}</td></tr>`).join('')+'</table>'};$('addInv').onclick=async()=>{workspace.inventory.push({host:$('host').value,ip:$('ipaddr').value,role:$('role').value});await persist();draw()};draw()}if(id==='regex')$('calc').onclick=()=>{let re=new RegExp($('re').value,'gm'),m=[...$('txt').value.matchAll(re)];o.textContent=m.map(x=>`Match at ${x.index}: ${x[0]}`).join('\n')||'No matches'};if(id==='viewer')$('calc').onclick=()=>{let s=$('txt').value.trim();try{if(s[0]==='{')o.textContent=JSON.stringify(JSON.parse(s),null,2);else if(s[0]==='<'){let doc=new DOMParser().parseFromString(s,'application/xml');if(doc.querySelector('parsererror'))throw Error('XML parse error');o.textContent=new XMLSerializer().serializeToString(doc).replace(/></g,'>\n<')}else{o.textContent=s.split('\n').map((l,i)=>String(i+1).padStart(3)+': '+l).join('\n')}}catch(e){o.textContent='Invalid: '+e.message}}}
async function initApp(){await openDB();await loadWorkspace();nav();show('dash');$('launcher').oninput=nav;document.addEventListener('keydown',e=>{if(e.key==='/'&&document.activeElement.tagName!=='INPUT'&&document.activeElement.tagName!=='TEXTAREA'){e.preventDefault();$('launcher').focus()}})}
ensureAuth().then(()=>{if(localStorage.session==='1'){$('login').classList.add('hidden');$('app').classList.remove('hidden');initApp()}});
</script>
</body>
</html>
HTML_EOF

  cat > "${UNIT_FILE}" <<UNIT_EOF
[Unit]
Description=Offline Network Engineering Toolkit
After=network.target

[Service]
Type=simple
WorkingDirectory=${APP_DIR}
ExecStart=/usr/bin/python3 -m http.server ${PORT} --bind 0.0.0.0 --directory ${APP_DIR}
Restart=on-failure
RestartSec=3
User=nobody
Group=nogroup
NoNewPrivileges=true
PrivateTmp=true
ProtectSystem=full
ProtectHome=true

[Install]
WantedBy=multi-user.target
UNIT_EOF

  chmod 0644 "${APP_FILE}" "${UNIT_FILE}"
  systemctl daemon-reload
  systemctl enable --now "${APP_NAME}.service"
  cat <<MSG
NetEng Toolkit installed.

Open: http://localhost:${PORT}/
Default login: admin / admin123

Manage the service:
  sudo systemctl status ${APP_NAME}
  sudo systemctl stop ${APP_NAME}
  sudo systemctl start ${APP_NAME}

Uninstall:
  sudo bash $0 uninstall
MSG
}

uninstall_app() {
  require_root "$@"
  systemctl disable --now "${APP_NAME}.service" >/dev/null 2>&1 || true
  rm -f "${UNIT_FILE}"
  systemctl daemon-reload
  rm -rf "${APP_DIR}"
  echo "NetEng Toolkit uninstalled."
}

case "${1:-}" in
  install) install_app "$@" ;;
  uninstall) uninstall_app "$@" ;;
  *)
    cat <<USAGE
Usage:
  sudo bash neteng-toolkit.sh install
  sudo bash neteng-toolkit.sh uninstall
  sudo systemctl status neteng-toolkit
USAGE
    exit 2
    ;;
esac
